package com.agmsolutions.fabrick_test.Model;import jakarta.persistence.*;import lombok.*;import java.math.BigDecimal;import java.time.LocalDate;import java.time.LocalDateTime;@Getter@Setter@ToString@NoArgsConstructor@AllArgsConstructor@Builder@Entity@Table(name = "transaction_history")public class TransactionHistory {        @Id    @GeneratedValue(strategy = GenerationType.IDENTITY)    private Long id;    private String transactionId;    private String operationId;    private LocalDate accountingDate;    private LocalDate valueDate;    private String typeEnumeration;    private String typeValue;    private BigDecimal amount;    private String currency;    private String description;    private Long accountId;    private LocalDateTime savedDate;}